  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('89a83f9c-b273-5652-9fe9-6540f60540cb', 'math-4eme', 'المحيط', 'معنى المحيط، محيط المربّع (4 × الضلع)، محيط المستطيل (2 × (الطول + العرض))، محيط المثلّث (مجموع الأضلاع)، وحلّ المسائل بما فيها إيجاد ضلعٍ من المحيط', '# ⚔️ المحيط — طولُ الحدود

> 💡 «المحيط هو الطريق حول الشكل: من يريد سياجًا لحديقةٍ يحسب محيطها أوّلًا.»

كم متْرًا من السلك يلزم لإحاطة لوحة؟ كم من السياج لحقلٍ مربّع؟ الجواب هو **المحيط**: مجموع أطوال أضلاع الشكل. في هذه البوّابة تتعلّم حساب محيط المربّع والمستطيل والمثلّث.

## 🧭 ما هو المحيط؟

**محيط** مضلّعٍ هو **مجموع أطوال أضلاعه** كلّها (طول الخطّ المغلق المحيط بالشكل). نقيسه بوحدات الطول (cm، m…).

## 🟦 محيط المربّع

بما أنّ أضلاع المربّع الأربعة **متساوية**، فإنّ محيطه يساوي أربعة أمثال الضلع:

$$محيط المربّع = 4 × الضلع$$

- _مثال:_ مربّعٌ ضلعه 5 cm: المحيط = 4 × 5 = **20 cm**.

## 🟩 محيط المستطيل

في المستطيل ضلعان متقابلان بالطول وضلعان بالعرض، فالمحيط يساوي ضِعفَ مجموع الطول والعرض:

$$محيط المستطيل = 2 × (الطول + العرض)$$

- _مثال:_ مستطيلٌ طوله 8 cm وعرضه 3 cm: المحيط = 2 × (8 + 3) = 2 × 11 = **22 cm**.

## 🔺 محيط المثلّث

محيط المثلّث هو **مجموع أطوال أضلاعه الثلاثة**:

$$محيط المثلّث = a + b + c$$

- _مثال:_ مثلّثٌ أضلاعه 4 cm و 5 cm و 6 cm: المحيط = 4 + 5 + 6 = **15 cm**.

## 🔄 إيجاد ضلعٍ من المحيط

نعكس العمليّة:

- **ضلع المربّع** = المحيط ÷ 4. مثال: محيطٌ 32 cm ⟸ الضلع = 32 ÷ 4 = 8 cm.
- **ضلع المثلّث متساوي الأضلاع** = المحيط ÷ 3.
- **عرض المستطيل** = (المحيط ÷ 2) − الطول.

> ⚠️ الفخّ الشائع: الخلط بين المحيط (مجموع الأطوال) وعمليّةٍ أخرى؛ تذكّر أنّ محيط المستطيل **ليس** الطول × العرض، بل 2 × (الطول + العرض).

> 🏆 صرت تحسب محيط الأشكال وتعكس العمليّة لإيجاد ضلع! استعدّ للبوّابة الأخيرة: **التناظر المحوريّ**.', '# 📜 ملخّص: المحيط

- **المحيط:** مجموع أطوال أضلاع المضلّع (طول الحدّ المحيط بالشكل)، يُقاس بوحدات الطول.
- **محيط المربّع** = 4 × الضلع، مثل ضلع 5 cm ⟸ المحيط 20 cm.
- **محيط المستطيل** = 2 × (الطول + العرض)، مثل 8 cm و 3 cm ⟸ المحيط 22 cm.
- **محيط المثلّث** = مجموع أضلاعه الثلاثة، مثل 4 + 5 + 6 = 15 cm.
- **إيجاد ضلعٍ من المحيط:** ضلع المربّع = المحيط ÷ 4؛ ضلع المثلّث متساوي الأضلاع = المحيط ÷ 3؛ عرض المستطيل = (المحيط ÷ 2) − الطول.
- **الفخّ:** محيط المستطيل ليس الطول × العرض، بل 2 × (الطول + العرض).', 15)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
